# static assets
^/_?tbp/                           public, max-age=31536000, stale-while-revalidate=3600, stale-if-error=86400
^/img/                              public, max-age=31536000, stale-while-revalidate=3600, stale-if-error=86400
^/tbco/                             public, max-age=31536000, stale-while-revalidate=3600, stale-if-error=86400
/android-chrome-512x512.png         public, max-age=86400, stale-while-revalidate=86400, stale-if-error=86400
/android-chrome-192x192.png         public, max-age=86400, stale-while-revalidate=86400, stale-if-error=86400
/apple-touch-icon-precomposed.png   public, max-age=86400, stale-while-revalidate=86400, stale-if-error=86400
/robots.txt                         public, max-age=86400, stale-while-revalidate=86400, stale-if-error=86400
/favicon.ico                        public, max-age=86400, stale-while-revalidate=86400, stale-if-error=86400
^/charting_library/                 public, max-age=86400, stale-while-revalidate=86400, stale-if-error=86400

# mapped to the legacy routes in theblock.co. the longer s-maxage rule exists because WordPress purges the api route cache when a post is published.
^/api/tbco/ping$                    private, must-revalidate, max-age=0
^/api/tbco/home$                    public, max-age=10, s-maxage=10, stale-while-revalidate=60, stale-if-error=86400
^/api/tbco/post/\d+$                public, max-age=10, s-maxage=300, stale-while-revalidate=60, stale-if-error=86400
^/api/tbco/amp-post/\d+$            public, max-age=10, s-maxage=300, stale-while-revalidate=60, stale-if-error=86400
