# heavy HTML content resources
^/$                                 public, max-age=10, s-maxage=10, stale-while-revalidate=60, stale-if-error=86400
^/latest                            public, max-age=3600, s-maxage=3600, stale-while-revalidate=60, stale-if-error=86400
^/latest-crypto-news                public, max-age=10, s-maxage=60, stale-while-revalidate=60, stale-if-error=86400
^/(post|linked)/\d+/[^/]+/preview$  private, must-revalidate, max-age=0
^/(post|linked)/\d+/[^/]+           public, max-age=60, s-maxage=300, stale-while-revalidate=60, stale-if-error=86400
^/data/.*                           public, max-age=10, s-maxage=10, stale-while-revalidate=60, stale-if-error=86400
^/ratings/.*                           public, max-age=10, s-maxage=10, stale-while-revalidate=60, stale-if-error=86400
^/category/*                        public, max-age=10, s-maxage=10, stale-while-revalidate=60, stale-if-error=86400
^/tag/*                             public, max-age=10, s-maxage=10, stale-while-revalidate=60, stale-if-error=86400
^/prices                            public, max-age=10, s-maxage=10, stale-while-revalidate=60, stale-if-error=86400

# default fallback
^/*                                 private, must-revalidate, max-age=0
